<!-- PROTOTYPE — mirrors the current /chat feature boundary with in-memory fixtures only. -->
<template>
  <main class="workspace">
    <section class="chat-shell">
      <header class="chat-header"><div class="persona-head"><i :class="['avatar', current.tone]">{{ current.persona[0] }}</i><span><b>{{ current.persona }}</b><small>{{ current.title }}</small></span></div><div class="header-actions"><div class="length"><button v-for="item in lengths" :key="item" :class="{ active: replyLength === item }" @click="replyLength = item">{{ item }}</button></div><button class="icon" @click="openConfig">⚙</button><button class="me">林</button></div></header>
      <nav class="conversation-tabs" aria-label="会话列表"><button v-for="conversation in conversations" :key="conversation.id" :class="{ active: currentId === conversation.id }" @click="selectConversation(conversation.id)"><i :class="['avatar', conversation.tone]">{{ conversation.persona[0] }}</i><span>{{ conversation.title }}</span><small>{{ conversation.updated }}</small></button></nav>
      <div class="perception"><span>☾ 平静 · 强度 7/10</span><div><b>你和 {{ current.persona }}</b><i><em></em></i><small>熟悉 72% · 下一个里程碑还差 8%</small></div></div>
      <div v-if="milestone" class="milestone">✦ 共同记忆已更新：{{ milestone }}</div>
      <section class="messages"><div v-if="messages.length === 1" class="greeting-switch"><button :disabled="greeting === 0" @click="greeting--">‹</button><span>开场白 {{ greeting + 1 }} / 3</span><button :disabled="greeting === 2" @click="greeting++">›</button></div><article v-for="message in messages" :key="message.id" :class="['message', message.role]"><i v-if="message.role === 'assistant'" :class="['avatar', current.tone]">{{ current.persona[0] }}</i><div class="bubble"><small>{{ message.role === 'assistant' ? current.persona : '林川' }} · {{ message.time }}</small><p>{{ message.text }}</p><span v-if="message.contract" class="contract">格式 ✓ · {{ message.contract }}</span></div><i v-if="message.role === 'user'" class="avatar me">林</i></article><div v-if="streaming" class="stage">{{ stages[stage] }}</div></section>
      <form class="composer" @submit.prevent="send"><textarea v-model="draft" :disabled="streaming" placeholder="输入消息…（Enter 发送，Shift+Enter 换行）" @keydown.enter.exact.prevent="send"></textarea><button v-if="!streaming" :disabled="!draft.trim()">发送</button><button v-else type="button" class="stop" @click="streaming = false">停止</button></form>
      <aside v-if="showHost" class="host-dock"><header><b>角色状态</b><button @click="showHost = false">×</button></header><div><span>体力</span><b>78 / 100</b></div><div><span>信任</span><b>72 / 100</b></div><div><span>旧城硬币</span><b>36</b></div><small>MVU 浏览器 Host · 本轮 3 项变量已同步</small></aside><button v-else class="host-open" @click="showHost = true">⌘ 卡 UI</button>
    </section>

    <div v-if="showCreate" class="overlay"><section class="modal create"><header><b>新建对话</b><button @click="closeModal">×</button></header><label>AI 角色<select v-model="create.persona"><option>伊澜</option><option>诺娅</option><option>阿斯特</option></select></label><label>我的角色<select v-model="create.user"><option>林川（旅行作家）</option><option>不指定</option></select></label><label>对话标题 <small>可选，留空自动生成</small><input v-model="create.title" placeholder="给这段对话取个名字…" /></label><label>预设<select v-model="create.preset"><option>叙事长篇（8 个 Prompt）</option><option>默认（无预设）</option></select></label><label>Prompt 模板<select v-model="create.template"><option>叙事长篇（首选）</option><option>系统默认（内置）</option></select></label><label>世界书 <small>多选、顺序敏感</small><select multiple><option selected>旧城档案</option><option>海港来信</option><option>王都礼仪</option></select></label><label>正则预设<select><option>叙事清理（6 条）</option><option>不使用</option></select></label><footer><RouterLink to="/personas">管理人设 →</RouterLink><span/><button class="ghost" @click="closeModal">取消</button><button class="primary" @click="createConversation">开始对话</button></footer></section></div>

    <div v-if="showConfig" class="overlay"><section class="modal config"><header><b>对话设置</b><button @click="closeModal">×</button></header><details open><summary>预设 / 模板 / 正则 / 世界书</summary><label>预设<select><option>叙事长篇</option></select></label><label>Prompt 模板<select><option>叙事长篇（首选）</option></select></label><label>世界书绑定<select multiple><option selected>旧城档案</option><option selected>海港来信</option></select></label></details><details><summary>采样参数</summary><div class="two"><label>Temperature<input value="0.82" /></label><label>Top P<input value="0.92" /></label><label>最大输出<input value="1400" /></label></div></details><details><summary>Token 预算</summary><p>总上下文 16,000 tokens</p><div class="budget"><i></i><i></i><i></i><i></i></div><small>历史 7,200 · 世界书 2,400 · 输出 1,400 · 安全余量 5,000</small></details><details><summary>对话状态变量 (12)</summary><p>体力 78　信任 72　旧城硬币 36</p><button class="ghost">重置变量</button></details><details><summary>功能开关</summary><label class="row">感知系统 <input type="checkbox" checked /></label><label class="row">卡界面危险能力 <input type="checkbox" /></label></details><details><summary>可见输出格式契约</summary><label>执行模式<select><option>继承账户默认（auto）</option><option>strict</option></select></label><p>上一轮：auto · passed · 覆盖 full</p></details><details><summary>Author’s Note 作者笔记</summary><textarea>保持雨夜的克制与温度；伊澜不会主动越界。</textarea><small>system · 深度 4 · 每 1 楼</small></details><footer><span/><button class="ghost" @click="closeModal">取消</button><button class="primary" @click="closeModal">保存覆盖</button></footer></section></div>
  </main>
