<script setup lang="ts">
import { computed, ref, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
type Message = { id: number; role: 'assistant' | 'user'; text: string; time: string; contract?: string }
const route = useRoute()
const router = useRouter()
const conversations = ref([{ id: 1, title: '月光落在旧书页上', persona: '伊澜', updated: '12 分钟前', tone: 'elen', messages: [{ id: 1, role: 'assistant', text: '雨落了一整晚。伊澜把最后一本书放回高处，回头看见你还站在门边。', time: '22:14' }, { id: 2, role: 'user', text: '我不是来借书的，只是想确认这里的灯还亮着。', time: '22:15' }, { id: 3, role: 'assistant', text: '“那就进来吧。”她把一盏小灯推到桌边，“今晚的故事，还没有写完。”', time: '22:15', contract: '状态栏已补全' }] as Message[] }, { id: 2, title: '海雾与来信', persona: '诺娅', updated: '昨天', tone: 'noa', messages: [{ id: 4, role: 'assistant', text: '港口的雾把每一封信都藏了起来。你愿意和我一起等吗？', time: '昨天 21:48' }] as Message[] }, { id: 3, title: '庭院里的下午茶', persona: '阿斯特', updated: '3 天前', tone: 'aster', messages: [{ id: 5, role: 'assistant', text: '午后的茶已经温好，阁下。今天想从哪一页开始？', time: '7 月 14 日' }] as Message[] }])
const currentId = ref(1); const current = computed(() => conversations.value.find(x => x.id === currentId.value) || conversations.value[0]); const messages = computed(() => current.value.messages)
const lengths = ['短', '中', '长']; const replyLength = ref('中'); const draft = ref(''); const streaming = ref(false); const stage = ref(0); const stages = ['正在创作草稿…', '正在结构化输出…', '正在渲染结构…']; const showCreate = ref(false); const showConfig = ref(false); const showHost = ref(false); const greeting = ref(0); const milestone = ref(''); const create = ref({ persona: '伊澜', user: '林川（旅行作家）', title: '', preset: '叙事长篇（8 个 Prompt）', template: '叙事长篇（首选）' })
function selectConversation(id: number) { currentId.value = id; milestone.value = ''; greeting.value = 0 }
function send() { const text = draft.value.trim(); if (!text || streaming.value) return; current.value.messages.push({ id: Date.now(), role: 'user', text, time: '刚刚' }); draft.value = ''; streaming.value = true; stage.value = 0; setTimeout(() => stage.value = 1, 350); setTimeout(() => stage.value = 2, 700); setTimeout(() => { current.value.messages.push({ id: Date.now() + 1, role: 'assistant', text: '伊澜停顿片刻，像是在替那句话找一个不会惊动雨声的位置。“我会记得。”', time: '刚刚', contract: '格式契约通过' }); streaming.value = false; milestone.value = '你们第一次共同守住了一个秘密' }, 1100) }
function openConfig() { showCreate.value = false; showConfig.value = true }
function closeModal() { showCreate.value = false; showConfig.value = false; if (route.path === '/chat/new' || route.path === '/chat/settings') router.push('/chat') }
function createConversation() { const id = Date.now(); conversations.value.unshift({ id, title: create.value.title || `与${create.value.persona}的新故事`, persona: create.value.persona, updated: '刚刚', tone: create.value.persona === '诺娅' ? 'noa' : create.value.persona === '阿斯特' ? 'aster' : 'elen', messages: [{ id: id + 1, role: 'assistant', text: greeting.value === 0 ? '你好。新的章节已经为你留出了第一页。' : '你终于来了。我还以为今晚要独自等雨停。', time: '刚刚' }] }); currentId.value = id; greeting.value = 0; closeModal() }
watch(() => route.path, path => { showCreate.value = path === '/chat/new'; showConfig.value = path === '/chat/settings'; showHost.value = path === '/chat/card-ui' }, { immediate: true })
</script>

